// Normalize + validate the incoming request
const body = $input.first().json.body || $input.first().json;

const jobId = body.jobId;
const postId = body.postId;
const type = body.type || body.content_type;
const postType = body.postType || body.style || 'lifestyle';
const callbackUrl = body.callbackUrl || body.callback_url || null;
const upload = body.upload || null;
const business = body.business || {};
const brandContext = body.brand_context || {};
const caption = body.caption || '';
const negativePrompt = body.negative_prompt || '';
const masterPrompt = body.master_prompt || null;
const referenceImageUrls = Array.isArray(body.referenceImageUrls) ? body.referenceImageUrls : 
                           (Array.isArray(body.reference_image_urls) ? body.reference_image_urls : 
                           (typeof body.reference_image_url === 'string' ? [body.reference_image_url] : []));
const featuredServices = Array.isArray(body.featuredServices) ? body.featuredServices : [];

function fail(code, message) {
  const e = new Error(message);
  e.httpCode = code;
  throw e;
}

if (!jobId) fail(400, 'Field "jobId" is required.');
if (!postId) fail(400, 'Field "postId" is required.');
if (!type || !['image', 'short_video'].includes(type)) fail(400, `Field "type" must be 'image' or 'short_video' (got '${type}').`);
if (!upload || !upload.presignedUrl || !upload.storageKey) fail(400, 'Field "upload.presignedUrl" and "upload.storageKey" are required.');
if (!callbackUrl) fail(400, 'Field "callbackUrl" is required.');

const refUrls = referenceImageUrls
  .filter((u) => typeof u === 'string' && u.trim())
  .slice(0, 3);

const mime = (upload.headers && (upload.headers['Content-Type'] || upload.headers['content-type'])) || (type === 'image' ? 'image/png' : 'video/mp4');

// Resolve aspect ratio
const aspect_ratio = body.aspect_ratio || (type === 'image' ? '1:1' : '9:16');

// Normalize scenes for video or single scene for image
let scenes = [];
if (type === 'short_video') {
  if (Array.isArray(body.scenes) && body.scenes.length > 0) {
    scenes = body.scenes
      .map((scene, index) => {
        if (typeof scene === 'string') {
          const prompt = scene.trim();
          return prompt.length >= 1 ? { prompt, scene_index: index, master_prompt: masterPrompt } : null;
        }
        const promptCandidate = typeof scene?.prompt === 'string' && scene.prompt.trim()
          ? scene.prompt.trim()
          : (typeof scene?.scene_prompt === 'string' && scene.scene_prompt.trim() ? scene.scene_prompt.trim() : '');
        return { ...scene, prompt: promptCandidate, scene_index: index, master_prompt: masterPrompt };
      })
      .filter(s => s && s.prompt);
  } else {
    // Fallback to body.prompt or caption
    const promptCandidate = body.prompt || caption || '';
    if (promptCandidate) {
      scenes = [{ prompt: promptCandidate.trim(), scene_index: 0, master_prompt: masterPrompt }];
    }
  }

  if (scenes.length === 0) {
    fail(400, 'Field "scenes" or "prompt" or "caption" is required for short_video.');
  }
} else {
  // For image
  const promptCandidate = body.prompt || caption || masterPrompt || '';
  if (!promptCandidate || promptCandidate.trim().length === 0) {
    fail(400, 'Field "prompt" or "caption" is required for image.');
  }
  scenes = [{ prompt: promptCandidate.trim(), master_prompt: masterPrompt }];
}

return [{
  json: {
    jobId,
    postId,
    type,
    postType,
    callbackUrl,
    upload: {
      presignedUrl: upload.presignedUrl,
      storageKey: upload.storageKey,
      publicUrl: upload.publicUrl || upload.presignedUrl.split('?')[0],
      headers: upload.headers || { 'Content-Type': mime },
      maxBytes: upload.maxBytes || (type === 'image' ? 10485760 : 52428800),
      mime,
    },
    business: {
      id: business.id || null,
      name: business.name || '',
      industry: business.industry || '',
      tone: business.tone || '',
      keywords: Array.isArray(business.keywords) ? business.keywords : [],
      logoPublicUrl: business.logoPublicUrl || null,
    },
    brand_context: brandContext,
    caption,
    negative_prompt: negativePrompt,
    master_prompt: masterPrompt,
    referenceImageUrls: refUrls,
    hasReference: refUrls.length > 0,
    featuredServices: featuredServices.map((s) => ({
      id: s.id,
      name: s.name,
      imagePublicUrl: s.imagePublicUrl || null,
    })),
    style: postType || 'lifestyle',
    aspect_ratio,
    scenes,
    metadata: { jobId, postId, type, postType, execution_id: $execution.id, requested_at: new Date().toISOString() },
  }
}];

// Wrap any thrown error and POST a fail callback to the backend, then rethrow.
// This is the error-handler for Validate Input.
const ctx = $('Validate Input').first().json || {};
const err = ($json && $json.error) || {};
const message = (err.message || err.description || 'Unknown error').toString().slice(0, 1000);
if (ctx.callbackUrl && ctx.jobId) {
  const payload = {
    jobId: ctx.jobId,
    error: { code: 'INVALID_REQUEST', message, type: ctx.type || 'unknown' },
  };
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: ctx.callbackUrl,
      headers: { 'X-Internal-Token': process.env.INTERNAL_API_KEY || '' },
      body: payload,
      json: true,
    });
  } catch (e) {}
}
return [{ json: { ok: false, error: message } }];

// Prepare reference URLs and ensure original data is passed through
const original = $('Validate Input').first().json || {};
const refUrls = Array.isArray(original.referenceImageUrls) ? original.referenceImageUrls : [];

const items = refUrls.map(url => ({
  json: { 
    referenceImageUrls: url,
    original: original
  }
}));

return items.length > 0 ? items : [{ json: { referenceImageUrls: [], original } }];

const items = $input.all();
const original = $('Validate Input').first().json;
const referenceImages = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  if (item.binary && item.binary.data) {
    const mimeType = item.binary.data.mimeType || 'image/jpeg';
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    if (buffer && buffer.length > 0) {
      referenceImages.push({
        mimeType,
        data: buffer.toString('base64')
      });
    }
  }
}

return [{
  json: {
    ...original,
    reference_images: referenceImages
  }
}];

const item = $input.first().json;

const systemPrompt = [
  'You are an expert visual content designer specialising in social media marketing for Thai SMEs.',
  '',
  'Given a marketing brief, brand context, and optionally reference images, write ONE detailed image-generation instruction for the Gemini native image model (Nano Banana).',
  '',
  'Rules:',
  '1. Reflect the brand tone, palette and any keywords provided.',
  '2. Describe composition, subject, lighting, colour scheme, mood, textures and camera framing.',
  '3. Optimise for a 1:1 social media post (or requested aspect ratio).',
  '4. Do NOT include text, typography, letters, words or logos in the image unless explicitly requested.',
  '5. If reference images are supplied, keep their subject while applying the marketing requirements (this will be used for image editing).',
  '6. Keep the instruction under 220 words, vivid, direct.',
  '7. Do NOT depict people, faces, hands, or body parts unless explicitly required.',
  '',
  'Respond ONLY with the final image instruction. No preamble, no explanations.'
].join('\n');

const promptText = item.caption || item.prompt || '';
const masterPrompt = item.master_prompt || null;
const combinedPrompt = masterPrompt && promptText
  ? `Master brief: ${masterPrompt}\nPrompt: ${promptText}`
  : (promptText || masterPrompt || '');

const userParts = [
  `Post type: ${item.postType || 'lifestyle'}`,
  `Caption/Prompt: ${combinedPrompt}`,
  `Business: ${item.business?.name || ''} (${item.business?.industry || 'general'})`,
  `Tone: ${item.business?.tone || 'friendly'}`,
  `Keywords: ${(item.business?.keywords || []).join(', ') || 'N/A'}`,
  `Aspect ratio: ${item.aspect_ratio || '1:1'}`,
];

if (item.brand_context && Object.keys(item.brand_context).length > 0) {
  userParts.push(`Brand context: ${JSON.stringify(item.brand_context)}`);
}
if (item.negative_prompt) {
  userParts.push(`Negative prompt (elements to avoid): ${item.negative_prompt}`);
}
if (item.featuredServices && item.featuredServices.length) {
  const services = item.featuredServices
    .map((s) => `${s.name}${s.imagePublicUrl ? ' [ref image available]' : ''}`)
    .join(', ');
  userParts.push(`Featured services to visualise: ${services}`);
}
if (item.hasReference) {
  userParts.push(`Reference images provided: ${item.referenceImageUrls.length}. The image model will receive them for editing.`);
}

const messages = [
  { role: 'system', content: systemPrompt }
];

const refImages = item.reference_images || [];
if (refImages.length > 0) {
  const contentParts = [
    { type: 'text', text: userParts.join('\n') }
  ];
  for (const refImg of refImages) {
    contentParts.push({
      type: 'image_url',
      image_url: {
        url: `data:${refImg.mimeType};base64,${refImg.data}`
      }
    });
  }
  messages.push({ role: 'user', content: contentParts });
} else {
  messages.push({ role: 'user', content: userParts.join('\n') });
}

return [{
  json: {
    original: item,
    api_body: {
      model: 'google/gemini-2.5-flash',
      messages: messages,
      temperature: 0.7,
      max_tokens: 4096,
    },
  }
}];

const originalData = $('Prepare Image Prompt').first().json.original;
const gptResponse = $('Enhance Image Prompt (Gemini)').first().json;
const enhancedPrompt = gptResponse.choices[0].message.content.trim();

const imageInstruction = [
  enhancedPrompt,
  '',
  'Create one clear image only.',
  'Keep the composition simple and fully visual.',
  'Do not include text, logos, letters, typography, people, faces, hands, or body parts unless the brief explicitly requires them.',
  'If the subject is food or a product, show it clearly centered and highly detailed.'
].join('\n');
const parts = [{ text: imageInstruction }];

const refImages = originalData.reference_images || [];
for (const refImg of refImages) {
  parts.push({
    inlineData: {
      mimeType: refImg.mimeType,
      data: refImg.data
    }
  });
}

const apiBody = {
  contents: [
    {
      role: 'user',
      parts: parts
    }
  ],
  generationConfig: {
    responseModalities: ['IMAGE'],
    imageConfig: {
      aspectRatio: originalData.aspect_ratio || '1:1'
    }
  }
};

if (originalData.negative_prompt) {
  apiBody.generationConfig.negativePrompt = originalData.negative_prompt;
}

return [{
  json: {
    original: originalData,
    enhanced_prompt: enhancedPrompt,
    aspect_ratio: originalData.aspect_ratio || '1:1',
    api_body: apiBody
  }
}];

const response = $input.first().json;
const original = $('Validate Input').first().json;
const prepareData = $('Build Image Request').first().json;

const candidates = response.candidates || [];
let base64 = null;
let mime = 'image/png';
for (const cand of candidates) {
  const parts = (cand.content && cand.content.parts) || [];
  for (const p of parts) {
    if (p.inlineData && p.inlineData.data) {
      base64 = p.inlineData.data;
      mime = p.inlineData.mimeType || mime;
      break;
    }
  }
  if (base64) break;
}
if (!base64) {
  const finishReason = (response && response.candidates && response.candidates[0] && response.candidates[0].finishReason) || 'UNKNOWN';
  const textParts = (response && response.candidates && response.candidates[0] && response.candidates[0].content && response.candidates[0].content.parts || [])
    .filter((p) => p && typeof p.text === 'string' && p.text.trim())
    .map((p) => p.text.trim())
    .join('\n');
  throw new Error(
    'Gemini image model returned no image. finishReason=' + finishReason + '; text=' + textParts.slice(0, 500)
  );
}

const ext = mime.includes('jpeg') ? 'jpg' : 'png';
const filename = 'img_' + original.jobId + '.' + ext;
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(base64, 'base64'),
  filename,
  mime,
);

return [{
  json: {
    original,
    enhanced_prompt: prepareData.enhanced_prompt,
    mime,
    size_bytes: Buffer.from(base64, 'base64').length,
  },
  binary: { data: binaryData },
}];

const ctx = $('Validate Input').first().json || {};
const err = ($json && $json.error) || {};
const message = (err.message || err.description || 'MinIO upload (image) failed').toString().slice(0, 1000);
if (ctx.callbackUrl && ctx.jobId) {
  return [{
    json: {
      callbackUrl: ctx.callbackUrl,
      payload: {
        jobId: ctx.jobId,
        error: { code: 'upload_failed', message, type: ctx.type || 'image' },
      },
    }
  }];
}
return [{ json: { ok: false, error: message } }];

let data = null;
try { data = $('Convert Image to Binary').first().json; } catch (e) {}
let putResp = null;
try { putResp = $('PUT Image to MinIO').first().json; } catch (e) {}
const status = (putResp && (putResp.statusCode || putResp.status)) || 0;
const body = putResp && putResp.body ? putResp.body.toString().slice(0, 300) : '';

if (!data || !data.original) {
  throw new Error('Prepare Image Callback: missing context (data/original).');
}
if (!(status >= 200 && status < 300)) {
  throw new Error('MinIO PUT for image returned status ' + status + ': ' + body);
}

const upload = data.original.upload;
const payload = {
  jobId: data.original.jobId,
  result: {
    storageKey: upload.storageKey,
    publicUrl: upload.publicUrl,
    mime: data.mime,
    sizeBytes: data.size_bytes,
    width: null,
    height: null,
    durationSec: null,
  },
};

return [{
  json: {
    callbackUrl: data.original.callbackUrl,
    payload,
  }
}];

