const item = $('Loop Scenes').item.json;
let referenceImage = null;

try {
  const inputItem = $input.first();
  if (inputItem && inputItem.binary && inputItem.binary.data) {
    const mimeType = inputItem.binary.data.mimeType || 'image/jpeg';
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    if (buffer && buffer.length > 0) {
      referenceImage = {
        mimeType,
        data: buffer.toString('base64')
      };
    }
  }
} catch (e) {
  // ignore
}

return [{
  json: {
    ...item,
    reference_image: referenceImage
  }
}];

const item = $input.first().json;

const systemPrompt = [
  'You are an expert short-form video content creator specialising in social media marketing.',
  '',
  'Given a marketing caption and brand context, write ONE detailed prompt for the Veo 3.1 video model.',
  '',
  'Rules:',
  '1. Describe scene composition, subject, action, camera movement and visual flow.',
  '2. Specify mood, lighting and colour grading.',
  '3. Optimise for 9:16 (vertical, social media).',
  '4. Keep the scene simple, focused and visually striking.',
  '5. Avoid on-screen text, typography or multi-character interactions.',
  '6. Do NOT depict people, faces, hands, or body parts unless explicitly required.',
  '7. For food or product ads, focus on the dish, ingredients, lighting, texture, motion.',
  '8. If a reference image is provided, treat it as the starting frame and keep the subject consistent.',
  '',
  'Respond ONLY with the final video prompt. No explanations.'
].join('\n');

const scenePrompt = item.prompt || '';
const masterPrompt = item.master_prompt || null;
const combinedPrompt = masterPrompt && scenePrompt
  ? `Master brief: ${masterPrompt}\nScene instruction: ${scenePrompt}`
  : (scenePrompt || masterPrompt || '');

const userParts = [
  `Post type: ${item.postType || 'lifestyle'}`,
  `Caption/Prompt: ${combinedPrompt}`,
  `Business: ${item.business?.name || ''} (${item.business?.industry || 'general'})`,
  `Tone: ${item.business?.tone || 'friendly'}`,
  `Keywords: ${(item.business?.keywords || []).join(', ') || 'N/A'}`,
  `Aspect ratio: ${item.aspect_ratio || '9:16'}`,
];

if (item.brand_context && Object.keys(item.brand_context).length > 0) {
  userParts.push(`Brand context: ${JSON.stringify(item.brand_context)}`);
}
if (item.negative_prompt) {
  userParts.push(`Negative prompt (elements to avoid): ${item.negative_prompt}`);
}
if (item.hasReference) {
  userParts.push('A reference image will be supplied as the starting frame / subject. Keep that subject consistent.');
}
userParts.push(masterPrompt && scenePrompt
  ? 'Important: keep this scene consistent with the master brief and the earlier scene progression, while still making the current action clear and visually distinct.'
  : 'Important: keep the scene food-focused, object-focused, and free from people, faces, hands, and body parts.');

const messages = [
  { role: 'system', content: systemPrompt }
];

const refImg = item.reference_image;
if (refImg) {
  messages.push({
    role: 'user',
    content: [
      { type: 'text', text: userParts.join('\n') },
      {
        type: 'image_url',
        image_url: {
          url: `data:${refImg.mimeType};base64,${refImg.data}`
        }
      }
    ]
  });
} else {
  messages.push({ role: 'user', content: userParts.join('\n') });
}

return [{
  json: {
    original: item,
    api_body: {
      model: 'google/gemini-2.5-flash',
      messages: messages,
      temperature: 0.7,
      max_tokens: 4096,
    },
  }
}];

const runIndex = $('Loop Scenes').context.currentRunIndex || 0;
let delaySeconds = 0;
if (runIndex > 0) {
  try {
    const lastExtract = $('Extract Task Info').first(0, runIndex - 1);
    if (lastExtract && lastExtract.json) {
      const lastSubmittedAt = new Date(lastExtract.json.submitted_at).getTime();
      const now = Date.now();
      const elapsedMs = now - lastSubmittedAt;
      const requiredMs = 65 * 1000; // 65 seconds to be safe
      if (elapsedMs < requiredMs) {
        delaySeconds = Math.ceil((requiredMs - elapsedMs) / 1000);
      }
    }
  } catch (e) {
    // fallback
  }
}
return [{ 
  json: {
    ...$input.first().json,
    delay_seconds: delaySeconds,
    should_wait: delaySeconds > 0
  }
}];

const runIndex = $('Loop Scenes').context.currentRunIndex || 0;
const originalData = $('Prepare Video Prompt').all(0, runIndex)[0].json.original;
const gptResponse = $('Enhance Video Prompt (Gemini)').all(0, runIndex)[0].json;
const enhancedPrompt = gptResponse.choices[0].message.content.trim();

let imageBase64 = null;
let mimeType = 'image/jpeg';

const refImg = originalData.reference_image;
if (refImg) {
  imageBase64 = refImg.data;
  mimeType = refImg.mimeType;
}

const aspectRatio = originalData.aspect_ratio === '16:9' ? '16:9' : '9:16';

// Check if this is a video extension based on loop index
const isExtension = runIndex > 0;
let previousVideoGcsUri = null;
if (isExtension) {
  try {
    const allRuns = $('Evaluate Video Status').all();
    if (allRuns && allRuns.length > 0) {
      previousVideoGcsUri = allRuns[allRuns.length - 1].json.gcs_url;
    }
  } catch (e) {
    // fallback
  }
}

const instance = { prompt: enhancedPrompt };
if (isExtension && previousVideoGcsUri) {
  instance.video = {
    gcsUri: previousVideoGcsUri,
    mimeType: 'video/mp4'
  };
} else if (imageBase64) {
  instance.image = {
    bytesBase64Encoded: imageBase64,
    mimeType: mimeType
  };
}

// Vertex AI Veo 3.1 video extension only supports exactly 7 seconds length for extension segments
const duration = isExtension ? 7 : 8;

const parameters = {
  storageUri: 'gs://' + ($env.GCP_VEO_OUTPUT_BUCKET || 'erp-ai-veo-bucket') + '/n8n-tmp/',
  sampleCount: 1,
  aspectRatio: aspectRatio,
  resolution: '720p',
  durationSeconds: duration
};
if (originalData.negative_prompt) {
  parameters.negativePrompt = originalData.negative_prompt;
}

return [{
  json: {
    original: originalData,
    enhanced_prompt: enhancedPrompt,
    is_extension: isExtension,
    reference_video_url: previousVideoGcsUri,
    api_body: {
      instances: [instance],
      parameters: parameters
    },
    submitted_at: new Date().toISOString()
  }
}];

const submitResponse = $input.first().json;
const jobData = $('Build Video Job').item.json;
const taskId = submitResponse.name;
if (!taskId) {
  throw new Error('Veo did not return an operation name. Response: ' + JSON.stringify(submitResponse).slice(0, 1000));
}
return [{
  json: {
    task_id: taskId,
    original: jobData.original,
    enhanced_prompt: jobData.enhanced_prompt,
    submitted_at: jobData.submitted_at || new Date().toISOString(),
  }
}];

const statusResponse = $input.first().json;
const taskInfo = $('Extract Task Info').first().json;

const elapsed = Date.now() - new Date(taskInfo.submitted_at).getTime();
const maxDuration = 10 * 60 * 1000;

if (elapsed > maxDuration) {
  return [{
    json: {
      status: 'failed',
      error_message: 'Video generation timed out after ' + Math.round(elapsed / 1000) + 's',
      task_id: taskInfo.task_id,
      original: taskInfo.original,
    }
  }];
}

const isDone = statusResponse.done === true;
let gcsUri = null;
let errorMsg = null;
let width = null, height = null, durationSec = null;

if (isDone) {
  const apiError = statusResponse.error || (statusResponse.response && statusResponse.response.error);
  if (apiError) {
    errorMsg = apiError.message || JSON.stringify(apiError);
  } else {
    const rai = statusResponse.response;
    if (rai && (Number(rai.raiMediaFilteredCount) > 0
        || (Array.isArray(rai.raiMediaFilteredReasons) && rai.raiMediaFilteredReasons.length > 0))) {
      const reasons = (rai.raiMediaFilteredReasons || []).join('; ');
      errorMsg = 'Content was filtered by Vertex AI safety check' + (reasons ? ': ' + reasons : '');
    } else {
      gcsUri = (statusResponse.response && statusResponse.response.videos && statusResponse.response.videos[0] && statusResponse.response.videos[0].gcsUri)
        || (statusResponse.response && statusResponse.response.generateVideoResponse && statusResponse.response.generateVideoResponse.generatedSamples && statusResponse.response.generateVideoResponse.generatedSamples[0] && statusResponse.response.generateVideoResponse.generatedSamples[0].video && statusResponse.response.generateVideoResponse.generatedSamples[0].video.uri)
        || null;
      if (!gcsUri) {
        errorMsg = 'Could not find video URI: ' + JSON.stringify(statusResponse).slice(0, 800);
      } else {
        const meta = (statusResponse.response && statusResponse.response.videos && statusResponse.response.videos[0]) || (statusResponse.response && statusResponse.response.generateVideoResponse && statusResponse.response.generateVideoResponse.generatedSamples && statusResponse.response.generateVideoResponse.generatedSamples[0]);
        width = (meta && meta.width) || null;
        height = (meta && meta.height) || null;
        durationSec = (meta && (meta.durationSeconds || meta.durationSec)) || 8;
      }
    }
  }
}

let normalizedStatus = 'processing';
if (isDone) {
  normalizedStatus = errorMsg ? 'failed' : 'completed';
}

return [{
  json: {
    status: normalizedStatus,
    gcs_url: gcsUri,
    error_message: errorMsg,
    task_id: taskInfo.task_id,
    original: taskInfo.original,
    enhanced_prompt: taskInfo.enhanced_prompt,
    width, height, durationSec,
  }
}];

const ctx = $('Validate Input').first().json || {};
const err = ($json && $json.error) || {};
const message = (err.message || err.description || 'MinIO upload (video) failed').toString().slice(0, 1000);
if (ctx.callbackUrl && ctx.jobId) {
  return [{
    json: {
      callbackUrl: ctx.callbackUrl,
      payload: {
        jobId: ctx.jobId,
        error: { code: 'upload_failed', message, type: ctx.type || 'short_video' },
      },
    }
  }];
}
return [{ json: { ok: false, error: message } }];

let evalData = null;
try { evalData = $('Evaluate Video Status').last().json; } catch (e) {}
let putResp = null;
try { putResp = $('PUT Video to MinIO').first().json; } catch (e) {}
const status = (putResp && (putResp.statusCode || putResp.status)) || 0;
const body = putResp && putResp.body ? putResp.body.toString().slice(0, 300) : '';

if (!evalData || !evalData.original) {
  throw new Error('Prepare Video Callback: missing context (evalData/original).');
}
if (!(status >= 200 && status < 300)) {
