const data = $input.first().json;
let jobId = null;
let callbackUrl = null;
try { jobId = $('Validate Input').first().json.jobId; } catch (e) {}
try { callbackUrl = $('Validate Input').first().json.callbackUrl; } catch (e) {}

const message = (data && data.error_message) ? String(data.error_message).slice(0, 1000) : 'Video generation failed.';
const lower = message.toLowerCase();
let code = 'VIDEO_GENERATION_FAILED';
let metadata = null;
if (lower.includes('safety check') || lower.includes('rai') || lower.includes('recitation') || lower.includes('blocked')) {
  code = 'content_safety';
  const reasons = [];
  const m = message.match(/safety check(?:\s*:\s*)?(.*)$/i);
  if (m && m[1]) reasons.push(m[1].trim());
  if (reasons.length) metadata = { raiMediaFilteredReasons: reasons };
}

const errPayload = {
  jobId: jobId,
  error: {
    code,
    message,
    taskId: data.task_id || null,
  },
};
if (metadata) errPayload.metadata = metadata;

return [{
  json: {
    callbackUrl: callbackUrl,
    payload: errPayload,
  }
}];
